import (
    "context"
    "github.com/openmeterio/openmeter/openmeter/billing"
)

type myApp struct{}

func (a *myApp) ValidateStandardInvoice(ctx context.Context, invoice billing.StandardInvoice) error {
    // validate without mutating invoice
    return nil
}

func (a *myApp) UpsertStandardInvoice(ctx context.Context, invoice billing.StandardInvoice) (*billing.UpsertStandardInvoiceResult, error) {
    result := billing.NewUpsertStandardInvoiceResult()
    // sync to external system, collect external IDs
    result.SetExternalID("ext-123")
    for _, line := range invoice.Lines.OrEmpty() {
        result.AddLineExternalID(line.ID, "line-ext-"+line.ID)
    }
    return result, nil
}

func (a *myApp) FinalizeStandardInvoice(ctx context.Context, invoice billing.StandardInvoice) (*billing.FinalizeStandardInvoiceResult, error) {
    result := billing.NewFinalizeStandardInvoiceResult()
    result.SetInvoiceNumber("INV-001")
    return result, nil
}

func (a *myApp) DeleteStandardInvoice(ctx context.Context, invoice billing.StandardInvoice) error {
    return nil
}
